// Resolve a responsive <img> prop bundle for an image (keyed by its /img
// filename, e.g. "about001.jpg"). Frames are fixed-height + cover, so the
// variants are described by DENSITY (x) descriptors keyed off height: the
// browser selects by display density (Retina → 2×/3×), independent of width.
export function imgProps(file) {
  const base = import.meta.env.BASE_URL
  const entry = images[file]
  if (!entry) throw new Error(`No optimized image for "${file}" — run npm run images`)
  const srcSet = entry.variants.map((v) => `${base}${v.src} ${v.density}x`).join(", ")
  return {
    src: `${base}${entry.variants[0].src}`,
    srcSet,
    width: entry.width,
    height: entry.height,
    placeholder: entry.placeholder,
  }
}

export default images
